from flask import Flask, request, jsonify
import jwt
from functools import wraps

class JWTWrapper:
    def __init__(self, secret_key, public_key=None):
        self.secret_key = secret_key
        self.public_key = public_key

    def encode_token(self, payload, algorithm='HS256'):
        return jwt.encode(payload, self.secret_key, algorithm=algorithm)

    def decode_token(self, token, algorithms):
        try:
            return jwt.decode(token, self.public_key or self.secret_key, algorithms=algorithms)
        except jwt.PyJWTError as e:
            return None

    def token_required(self, algorithms):
        def decorator(f):
            @wraps(f)
            def decorated(*args, **kwargs):
                token = request.headers.get('Authorization')
                if not token:
                    return jsonify({'message': 'Token is missing!'}), 403
                token = token.split()[1]  # Assuming "Bearer <token>"
                payload = self.decode_token(token, algorithms)
                if not payload:
                    return jsonify({'message': 'Token is invalid!'}), 403
                return f(payload, *args, **kwargs)
            return decorated
        return decorator

